mapper.select:
/* com.erns.coching.sysProp.mapper.SysPropDAO.getList */
SELECT ZZ.* FROM ( SELECT
, A1.MEMB_SEQ AS MEMB_SEQ , A1.MEMB_ID AS MEMB_ID , A1.MEMB_NAME AS MEMB_NAME FROM T_SYS_PROP_INF AA LEFT OUTER JOIN T_MEMB_INF A1 ON AA.CHNR = A1.MEMB_SEQ
ORDER BY RGT_DTTM DESC ) AS ZZ
OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.sysProp.mapper.SysPropDAO.load */

SELECT

FROM T_SYS_PROP_INF AA

	AND AA.SYS_KEY= #{sysKey, jdbcType=VARCHAR}

/* com.erns.coching.sysProp.mapper.SysPropDAO.loadVo */

SELECT

FROM T_SYS_PROP_INF AA

	AND AA.SYS_KEY= #{value, jdbcType=VARCHAR}
